CREATE EXTENSION IF NOT EXISTS vector;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_type
        WHERE typname = 'genero_enum'
    ) THEN
        CREATE TYPE genero_enum AS ENUM (
            'ROMANCE',
            'FANTASIA',
            'FICCAO',
            'TERROR',
            'SUSPENSE',
            'CIENCIA',
            'BIOGRAFIA',
            'CLASSICO',
            'INFANTIL',
            'POEMA'
        );
    END IF;
END
$$;

CREATE TABLE IF NOT EXISTS livros (
    id VARCHAR(20) PRIMARY KEY,
    titulo VARCHAR(255),
    autor VARCHAR(255),
    genero genero_enum,
    ano INT,
    numero_paginas INT,
    descricao TEXT,
    embedding VECTOR(384)
);

-- Para uma base pequena, a busca exata já é suficiente.
-- Em bases maiores, este índice acelera a distância por cosseno.
CREATE INDEX IF NOT EXISTS livros_embedding_hnsw_idx
ON livros USING hnsw (embedding vector_cosine_ops);

